### 示例 1：构建含 3 个节点的链表 `1 → 3 → 5`（C 语言）  
```c
#include <stdio.h>
#include <stdlib.h>

struct ListNode {
    int data;
    struct ListNode *next;
};

int main() {
    // 步骤1：创建节点（动态分配）
    struct ListNode *node1 = (struct ListNode*)malloc(sizeof(struct ListNode));
    struct ListNode *node2 = (struct ListNode*)malloc(sizeof(struct ListNode));
    struct ListNode *node3 = (struct ListNode*)malloc(sizeof(struct ListNode));

    // 步骤2：赋值数据
    node1->data = 1;
    node2->data = 3;
    node3->data = 5;

    // 步骤3：建立链接（关键！）
    node1->next = node2;  // node1 指向 node2
    node2->next = node3;  // node2 指向 node3
    node3->next = NULL;   // node3 是尾节点

    // 步骤4：设置头指针
    struct ListNode *head = node1;

    // 遍历打印
    struct ListNode *p = head;
    while (p != NULL) {
        printf("%d ", p->data);
        p = p->next;
    }
    // 输出：1 3 5

    // ✅ 内存释放（重要！防止泄漏）
    free(node1); free(node2); free(node3);
    return 0;
}
```

