## 示例  

### C语言完整实现（含测试）  
```c
#include <stdio.h>
#include <stdlib.h>
#define MAXSIZE 10

typedef struct {
    int data[MAXSIZE];
    int top; // 指向下一个空位（栈中元素个数）
} SeqStack;

// 初始化空栈
void InitStack(SeqStack *S) {
    S->top = 0;
}

// 判空
int IsEmpty(SeqStack S) {
    return S.top == 0;
}

// 判满
int IsFull(SeqStack S) {
    return S.top == MAXSIZE;
}

// 入栈
int Push(SeqStack *S, int x) {
    if (IsFull(*S)) {
        printf("错误：栈已满！\n");
        return 0; // 失败
    }
    S->data[S->top] = x;
    S->top++;
    return 1; // 成功
}

// 出栈
int Pop(SeqStack *S, int *x) {
    if (IsEmpty(*S)) {
        printf("错误：栈为空！\n");
        return 0;
    }
    S->top--;
    *x = S->data[S->top];
    return 1;
}

// 获取栈顶元素
int GetTop(SeqStack S, int *x) {
    if (IsEmpty(S)) {
        printf("错误：栈为空！\n");
        return 0;
    }
    *x = S.data[S.top - 1];
    return 1;
}

// 主函数测试
int main() {
    SeqStack S;
    InitStack(&S);

    // 压入 1, 2, 3
    Push(&S, 1); Push(&S, 2); Push(&S, 3);
    printf("栈中元素个数：%d\n", S.top); // 输出：3

    // 查看栈顶
    int topVal;
    GetTop(S, &topVal);
    printf("栈顶元素：%d\n", topVal); // 输出：3

    // 弹出两次
    Pop(&S, &topVal); printf("弹出：%d\n", topVal); // 3
    Pop(&S, &topVal); printf("弹出：%d\n", topVal); // 2

    printf("剩余元素个数：%d\n", S.top); // 输出：1
    return 0;
}
```

### 运行结果  
```
栈中元素个数：3  
栈顶元素：3  
弹出：3  
弹出：2  
剩余元素个数：1  
```

