## 示例  

### 完整可运行示例（C语言）  
```c
#include <stdio.h>
#include <stdlib.h>

// （结构体定义同上）

// 初始化
Status InitList(SeqList *L) {
    L->elem = (ElemType*)malloc(INIT_SIZE * sizeof(ElemType));
    if (!L->elem) return ERROR; // 内存分配失败
    L->length = 0;
    L->capacity = INIT_SIZE;
    return OK;
}

// 尾部插入（高效）
Status ListInsertLast(SeqList *L, ElemType e) {
    if (L->length >= L->capacity) {
        ElemType *newbase = (ElemType*)realloc(L->elem,
            (L->capacity + INCREASE) * sizeof(ElemType));
        if (!newbase) return ERROR;
        L->elem = newbase;
        L->capacity += INCREASE;
    }
    L->elem[L->length++] = e;
    return OK;
}

// 按位插入（通用）
Status ListInsert(SeqList *L, int i, ElemType e) {
    if (i < 1 || i > L->length + 1) return ERROR; // 位置非法
    if (L->length >= L->capacity) { /* 扩容逻辑同上 */ }

    // 从最后一个元素开始，向后移动至第i位腾出空间
    for (int j = L->length; j >= i; j--) {
        L->elem[j] = L->elem[j-1];
    }
    L->elem[i-1] = e; // 注意：i从1起，数组下标从0起
    L->length++;
    return OK;
}

// 主函数演示
int main() {
    SeqList L;
    InitList(&L);

    // 插入 10, 20, 30 到尾部
    ListInsertLast(&L, 10);
    ListInsertLast(&L, 20);
    ListInsertLast(&L, 30);

    // 在位置2插入15 → [10,15,20,30]
    ListInsert(&L, 2, 15);

    printf("顺序表内容：");
    for (int i = 0; i < L.length; i++) {
        printf("%d ", L.elem[i]);
    }
    printf("\n长度：%d，容量：%d\n", L.length, L.capacity);

    free(L.elem); // 记得释放内存！
    return 0;
}
```
**输出**：  
```
顺序表内容：10 15 20 30   
长度：4，容量：10
```

### 常见错误调试指南
